insert into public.products (id, cat, price, stock, img_seed, img, name_es, name_va, desc_es, desc_va, sort_order) values
  ('int-01', 'interior', 24.9, 12, 130, null, 'Monstera Deliciosa', 'Monstera Deliciosa', 'La icónica costilla de Adán. Hojas perforadas espectaculares, perfecta para dar un toque tropical a cualquier estancia luminosa. Riego moderado.', 'La icònica costella d''Adam. Fulles perforades espectaculars, perfecta per a donar un toc tropical a qualsevol estança lluminosa. Reg moderat.', 0),
  ('int-02', 'interior', 39.5, 6, 120, null, 'Ficus Lyrata (Pandurata)', 'Ficus Lyrata (Pandurata)', 'Árbol de hojas grandes en forma de lira. Estiliza cualquier salón. Le encanta la luz indirecta brillante.', 'Arbre de fulles grans en forma de lira. Estilitza qualsevol saló. Li encanta la llum indirecta brillant.', 1),
  ('int-03', 'interior', 8.9, 40, 110, null, 'Potos (Pothos)', 'Potus (Pothos)', 'La planta colgante más agradecida. Purifica el aire y crece rápido con muy pocos cuidados.', 'La planta penjant més agraïda. Purifica l''aire i creix ràpid amb molt pocs cures.', 2),
  ('int-04', 'interior', 14.5, 18, 90, null, 'Sansevieria (Lengua de Suegra)', 'Sanseviera (Llengua de Sogra)', 'Resistente, elegante y casi indestructible. Ideal para principiantes y espacios con poca luz.', 'Resistent, elegant i quasi indestructible. Ideal per a principiants i espais amb poca llum.', 3),
  ('int-05', 'interior', 18, 15, 140, null, 'Spathiphyllum (Cuna de Moisés)', 'Spathiphyllum (Bressol de Moisés)', 'Hojas verde brillante y flores blancas elegantes. Excelente purificadora del aire.', 'Fulles verd brillant i flors blanques elegants. Excel·lent purificadora de l''aire.', 4),
  ('int-06', 'interior', 6.5, 50, 60, null, 'Cactus surtidos (maceta 10cm)', 'Cactus assortits (test 10cm)', 'Selección de cactus pequeños en macetas decorativas. Mínimos cuidados, máximo carácter.', 'Selecció de cactus xicotets en testos decoratius. Mínims cures, màxim caràcter.', 5),
  ('int-07', 'interior', 12, 22, 100, null, 'Aloe Vera', 'Aloe Vera', 'Suculenta medicinal con múltiples propiedades. Requiere mucha luz y poco riego.', 'Suculenta medicinal amb múltiples propietats. Requereix molta llum i poc reg.', 6),
  ('int-08', 'interior', 22, 10, 160, null, 'Calathea Orbifolia', 'Calathea Orbifolia', 'Hojas redondeadas con rayas plateadas. Una joya para amantes del follaje exótico.', 'Fulles arredonides amb ratlles platejades. Una joia per a amants del fullatge exòtic.', 7),
  ('int-09', 'interior', 16.9, 30, 300, null, 'Orquídea Phalaenopsis', 'Orquídia Phalaenopsis', 'La orquídea más elegante y duradera. Floración prolongada en tonos blancos, rosas o lilas.', 'L''orquídia més elegant i duradora. Floració prolongada en tons blancs, roses o liles.', 8),
  ('int-10', 'interior', 11.5, 24, 115, null, 'Helecho de Boston', 'Falguera de Boston', 'Follaje frondoso y aireado. Perfecto para baños y zonas con humedad alta.', 'Fullatge frondós i airejat. Perfecte per a banys i zones amb humitat alta.', 9),
  ('ext-01', 'exterior', 7.5, 60, 270, null, 'Lavanda', 'Espígol', 'Aroma inconfundible y flores moradas. Atrae polinizadores y tolera muy bien la sequía.', 'Aroma inconfusible i flors morades. Atrau pol·linitzadors i tolera molt bé la sequera.', 10),
  ('ext-02', 'exterior', 5.9, 80, 80, null, 'Romero', 'Romer', 'Aromática mediterránea imprescindible. Resistente y útil tanto en jardín como en cocina.', 'Aromàtica mediterrània imprescindible. Resistent i útil tant al jardí com a la cuina.', 11),
  ('ext-03', 'exterior', 4.5, 100, 350, null, 'Geranios (variedades)', 'Geranis (varietats)', 'El clásico de los balcones mediterráneos. Floración abundante de primavera a otoño.', 'El clàssic dels balcons mediterranis. Floració abundant de primavera a tardor.', 12),
  ('ext-04', 'exterior', 13.5, 18, 40, null, 'Jazmín blanco', 'Gessamí blanc', 'Nuestra planta insignia. Flores blancas perfumadas que llenan el jardín de aroma en verano.', 'La nostra planta insígnia. Flors blanques perfumades que omplen el jardí d''aroma a l''estiu.', 13),
  ('ext-05', 'exterior', 19.9, 14, 320, null, 'Buganvilla', 'Bugamvíl·lia', 'Espectaculares brácteas en fucsia, rojo o naranja. Resistente al calor y a la sal marina.', 'Espectaculars bràctees en fucsia, roig o taronja. Resistent a la calor i a la sal marina.', 14),
  ('ext-06', 'exterior', 15, 12, 290, null, 'Hortensia', 'Hortènsia', 'Grandes inflorescencias en azul, rosa o blanco. Prefiere semisombra y riego constante.', 'Grans inflorescències en blau, rosa o blanc. Prefereix semiombra i reg constant.', 15),
  ('ext-07', 'exterior', 21.5, 9, 340, null, 'Rosal trepador', 'Roser enfiladís', 'Para pérgolas, vallas y muros. Disponible en múltiples colores y variedades aromáticas.', 'Per a pèrgoles, tanques i murs. Disponible en múltiples colors i varietats aromàtiques.', 16),
  ('ext-08', 'exterior', 12, 16, 310, null, 'Hibisco', 'Hibisc', 'Grandes flores tropicales en rojo, rosa o amarillo. Perfecto para zonas soleadas.', 'Grans flors tropicals en roig, rosa o groc. Perfecte per a zones assolellades.', 17),
  ('ext-09', 'exterior', 3.5, 120, 70, null, 'Margaritas', 'Margarides', 'Flores alegres de pétalos blancos y centro amarillo. Las imprescindibles del jardín.', 'Flors alegres de pètals blancs i centre groc. Les imprescindibles del jardí.', 18),
