  ('arb-01', 'arboles', 89, 5, 95, null, 'Olivo decorativo', 'Olivera decorativa', 'Pieza única de carácter mediterráneo. Ideal como ejemplar central en jardines y patios.', 'Peça única de caràcter mediterrani. Ideal com a exemplar central en jardins i patis.', 20),
  ('arb-02', 'arboles', 45, 8, 55, null, 'Limonero', 'Llimera', 'Frutal mediterráneo por excelencia. Produce limones durante gran parte del año.', 'Fruiter mediterrani per excel·lència. Produeix llimes durant gran part de l''any.', 21),
  ('arb-03', 'arboles', 49, 7, 30, null, 'Naranjo', 'Taronger', 'Aromáticas flores de azahar y deliciosas naranjas. Un clásico del jardín valenciano.', 'Aromàtiques flors de tarongina i delicioses taronges. Un clàssic del jardí valencià.', 22),
  ('arb-04', 'arboles', 32, 12, 145, null, 'Ciprés', 'Xiprer', 'Perfecto para setos y como ejemplar aislado. Crecimiento rápido y porte elegante.', 'Perfecte per a tanques i com a exemplar aïllat. Creixement ràpid i port elegant.', 23),
  ('arb-05', 'arboles', 17, 20, 0, null, 'Adelfa', 'Baladre', 'Arbusto mediterráneo muy resistente. Floración espectacular en rojo, rosa o blanco.', 'Arbust mediterrani molt resistent. Floració espectacular en roig, rosa o blanc.', 24),
  ('arb-06', 'arboles', 75, 4, 305, null, 'Magnolia grandiflora', 'Magnòlia grandiflora', 'Árbol majestuoso de flores blancas y aromáticas. Ejemplar que marca el paisaje.', 'Arbre majestuós de flors blanques i aromàtiques. Exemplar que marca el paisatge.', 25),
  ('arb-07', 'arboles', 120, 3, 75, null, 'Palmera Phoenix', 'Palmera Phoenix', 'Aporta carácter tropical a cualquier jardín. Muy resistente a la salinidad y al calor.', 'Aporta caràcter tropical a qualsevol jardí. Molt resistent a la salinitat i a la calor.', 26),
  ('arb-08', 'arboles', 14, 25, 125, null, 'Boj', 'Boix', 'Ideal para setos formales y topiaria. Hoja perenne pequeña y muy compacta.', 'Ideal per a tanques formals i topiària. Fulla perenne xicoteta i molt compacta.', 27),
  ('sus-01', 'sustratos', 8.5, 50, 25, null, 'Sustrato universal 20L', 'Substrat universal 20L', 'Mezcla equilibrada apta para la mayoría de plantas. Buen drenaje y nutrición.', 'Mescla equilibrada apta per a la majoria de plantes. Bon drenatge i nutrició.', 28),
  ('sus-02', 'sustratos', 4.9, 40, 20, null, 'Sustrato para cactus 5L', 'Substrat per a cactus 5L', 'Mezcla mineral con perlita y arena. Drenaje óptimo para suculentas y cactus.', 'Mescla mineral amb perlita i arena. Drenatge òptim per a suculentes i cactus.', 29),
  ('sus-03', 'sustratos', 18.9, 25, 15, null, 'Turba rubia 50L', 'Torba rossa 50L', 'Turba de calidad profesional para semilleros y plantación. Estructura aireada.', 'Torba de qualitat professional per a planters i plantació. Estructura airejada.', 30),
  ('sus-04', 'sustratos', 12.5, 30, 50, null, 'Abono líquido universal 1L', 'Adob líquid universal 1L', 'Aporta los nutrientes esenciales para un crecimiento sano. Dosificador incluido.', 'Aporta els nutrients essencials per a un creixement sa. Dosificador inclòs.', 31),
  ('sus-05', 'sustratos', 9.9, 35, 35, null, 'Humus de lombriz 5kg', 'Humus de cuc 5kg', 'Abono orgánico 100% natural. Mejora la estructura del suelo y la microbiota.', 'Adob orgànic 100% natural. Millora l''estructura del sòl i la microbiota.', 32),
  ('mac-01', 'macetas', 9.5, 40, 22, null, 'Maceta terracota 25cm', 'Test terracota 25cm', 'Clásica maceta de barro cocido. Transpirable y de larga duración.', 'Clàssic test de fang cuit. Transpirable i de llarga durada.', 33),
  ('mac-02', 'macetas', 24.9, 18, 200, null, 'Maceta cerámica decorativa', 'Test ceràmic decoratiu', 'Cerámica esmaltada en varios colores. Acabado mate, ideal para interior.', 'Ceràmica esmaltada en diversos colors. Acabat mat, ideal per a interior.', 34),
  ('mac-03', 'macetas', 17.5, 22, 18, null, 'Jardinera rectangular 60cm', 'Jardinera rectangular 60cm', 'Perfecta para balcones y terrazas. Plato recogegotas integrado.', 'Perfecta per a balcons i terrasses. Plat arreplegagotes integrat.', 35),
  ('mac-04', 'macetas', 29, 12, 250, null, 'Set de herramientas de jardín', 'Joc d''eines de jardí', 'Pala, transplantador y rastrillo. Mango ergonómico de madera.', 'Pala, transplantador i rasclet. Mànec ergonòmic de fusta.', 36),
  ('mac-05', 'macetas', 22.5, 14, 240, null, 'Regadera metálica 5L', 'Regadora metàl·lica 5L', 'Diseño clásico en zinc. Roseta desmontable para riego suave.', 'Disseny clàssic en zinc. Roseta desmuntable per a un reg suau.', 37),
  ('flo-01', 'flores', 28, 8, 320, null, 'Ramo de temporada', 'Ram de temporada', 'Selección floral fresca de nuestros mejores proveedores. Compuesto a mano por nuestra floristería.', 'Selecció floral fresca dels nostres millors proveïdors. Compost a mà per la nostra floristeria.', 38),
  ('flo-02', 'flores', 3.5, 120, 290, null, 'Pensamientos', 'Pensaments', 'Las flores del invierno. Resisten el frío y aportan color cuando todo descansa.', 'Les flors de l''hivern. Resistixen el fred i aporten color quan tot descansa.', 39),
  ('flo-03', 'flores', 6.9, 40, 330, null, 'Ciclamen', 'Ciclamen', 'Floración invernal espectacular en macetas. Tonos rosados, blancos y rojos.', 'Floració hivernal espectacular en testos. Tons rosats, blancs i rojos.', 40),
  ('flo-04', 'flores', 9.5, 30, 45, null, 'Crisantemos', 'Crisantems', 'Disponibles en gran variedad de colores. La flor del otoño por excelencia.', 'Disponibles en gran varietat de colors. La flor de la tardor per excel·lència.', 41),
  ('flo-05', 'flores', 11.9, 20, 5, null, 'Poinsettia (Flor de Pascua)', 'Poinsettia (Flor de Pasqua)', 'La planta navideña por antonomasia. Sus brácteas rojas alegran cualquier rincón.', 'La planta nadalenca per antonomàsia. Les seues bràctees roges alegren qualsevol racó.', 42)
